scripts.postResponse:
rq.test('Status is success', function(){ rq.expect(rq.response.code).to.be.oneOf([200,201]); });
let json = {}; try { json = rq.response.json(); } catch(e) {}
const reference = json.reference || '';
const paymentId = json.payment_id || '';
if (reference) rq.collectionVariables.set('cohort_reference', reference);
if (paymentId) rq.collectionVariables.set('cohort_payment_id', paymentId);
rq.test('Reference captured when enrollment is valid', function(){
  if (rq.collectionVariables.get('cohort_enrollment_id')) rq.expect(reference).to.be.a('string').and.not.empty;
  else rq.expect(true).to.eql(true);
});
